import{_ as i,o as t,c as a,ao as e}from"./chunks/framework.C2J2gf9T.js";const k=JSON.parse('{"title":"Continuum Absorption","description":"","frontmatter":{},"headers":[],"relativePath":"continuum.md","filePath":"continuum.md","lastUpdated":null}'),n={name:"continuum.md"};function l(r,s,p,o,h,d){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="Continuum-Absorption" tabindex="-1">Continuum Absorption <a class="header-anchor" href="#Continuum-Absorption" aria-label="Permalink to &quot;Continuum Absorption {#Continuum-Absorption}&quot;">​</a></h1><p>Discrete spectral lines are not the whole story. Two slowly varying &quot;continuum&quot; contributions matter for accurate atmospheric radiative transfer, and <code>AtmosphericAbsorption.jl</code> exposes both:</p><ul><li><p><strong>MT_CKD water-vapor continuum</strong> — the self- and foreign-broadened water-vapor continuum (the far-wing and weak-interaction absorption that the line-by-line sum truncates away), using the bundled AER v4.2 reference data.</p></li><li><p><strong>Collision-induced absorption (CIA)</strong> — transient absorption by colliding pairs (e.g. O₂–O₂, N₂–N₂) that have no permanent dipole, read from HITRAN <code>.cia</code> files.</p></li></ul><p>Both are returned as <strong>cross-section quantities</strong>. To get optical depth you multiply by the appropriate number densities and the path length yourself — that integration lives in your RT code, not here. The two continua use different cross-section conventions because they involve different numbers of molecules (see the units notes below).</p><h2 id="Water-vapor-continuum-MT_CKD" tabindex="-1">Water-vapor continuum (MT_CKD) <a class="header-anchor" href="#Water-vapor-continuum-MT_CKD" aria-label="Permalink to &quot;Water-vapor continuum (MT_CKD) {#Water-vapor-continuum-MT_CKD}&quot;">​</a></h2><p>The workflow has three steps: load the bundled table, build a band interpolated onto your wavenumber grid, then evaluate at a given temperature and the relevant partial pressures.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AtmosphericAbsorption</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Wavenumber grid in cm⁻¹</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">grid </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> collect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2350.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.01</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2450.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Load the bundled AER MT_CKD v4.2 reference table</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tbl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> load_mtckd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Interpolate the continuum onto your grid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">band </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> build_mtckd_band</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tbl, grid)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Evaluate the cross-section [cm²/molecule]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T      </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 250.0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # temperature [K]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p_h2o  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 12.0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # water-vapor partial pressure [hPa]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p_dry  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 988.0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # dry-air partial pressure [hPa]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">σ_h2o  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> h2o_continuum</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(band, T, p_h2o, p_dry)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vector, cm²/molecule</span></span></code></pre></div><p><code>h2o_continuum</code> returns the water-vapor continuum cross-section in <strong>cm²/molecule</strong>, one value per grid point. It combines the self-continuum (scaling with the water-vapor partial pressure <code>p_h2o</code>) and the foreign-continuum (scaling with the dry-air partial pressure <code>p_dry</code>).</p><p>To convert to optical depth, multiply by the water-vapor number density and the path length over each layer in your RT code.</p><div class="tip custom-block"><p class="custom-block-title">Temperature dependence The water-vapor <strong>self-continuum strengthens as temperature drops</strong> — it has a strong negative temperature coefficient. Evaluating it at a single representative temperature for a thick, cold layer will misestimate the absorption; sample it per layer at the layer temperature. :::</p><h2 id="Collision-induced-absorption-CIA" tabindex="-1">Collision-induced absorption (CIA) <a class="header-anchor" href="#Collision-induced-absorption-CIA" aria-label="Permalink to &quot;Collision-induced absorption (CIA) {#Collision-induced-absorption-CIA}&quot;">​</a></h2><p>CIA is read directly from a HITRAN <code>.cia</code> file. As with MT_CKD, you load and interpolate onto your grid once, then evaluate per temperature.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AtmosphericAbsorption</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">grid </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> collect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7000.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8500.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cm⁻¹</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Load and interpolate a HITRAN .cia file onto the grid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tcia </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> load_cia</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;O2-O2_2024.cia&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, grid)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Binary cross-section at a given temperature [cm⁵/molecule²]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T   </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 280.0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">σ_cia </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> cia_cross_section</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(tcia, T)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vector, cm⁵/molecule²</span></span></code></pre></div><p><code>cia_cross_section</code> returns the <strong>binary</strong> cross-section σ_AB(ν, T) in <strong>cm⁵/molecule²</strong>. The extra factors of length and molecule count (relative to the cm²/molecule of a line-by-line cross-section) reflect that CIA scales with the product of <em>two</em> number densities. For an O₂–O₂ pair the layer optical depth is</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>τ(ν) = σ_AB(ν, T) · n_O₂² · L</span></span></code></pre></div><p>where <code>n_O₂</code> is the O₂ number density [molecules/cm³] and <code>L</code> is the path length [cm]. For an unlike pair A–B, use <code>n_A · n_B</code> in place of <code>n_O₂²</code>.</p><div class="tip custom-block"><p class="custom-block-title">Multi-band .cia files and temperature HITRAN <code>.cia</code> files often contain several spectral bands, each tabulated on its own temperature grid. <code>load_cia</code> and <code>cia_cross_section</code> perform the temperature interpolation <strong>per frequency</strong>, so files spanning multiple bands (with differing temperature coverage) are handled correctly — each grid point is interpolated using the temperatures available for its band. :::</p><h2 id="Units-summary" tabindex="-1">Units summary <a class="header-anchor" href="#Units-summary" aria-label="Permalink to &quot;Units summary {#Units-summary}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Quantity</th><th style="text-align:right;">Function</th><th style="text-align:right;">Units</th></tr></thead><tbody><tr><td style="text-align:right;">Wavenumber grid</td><td style="text-align:right;">—</td><td style="text-align:right;">cm⁻¹</td></tr><tr><td style="text-align:right;">Temperature <code>T</code></td><td style="text-align:right;">—</td><td style="text-align:right;">K</td></tr><tr><td style="text-align:right;">Partial pressures <code>p_h2o</code>, <code>p_dry</code></td><td style="text-align:right;">—</td><td style="text-align:right;">hPa</td></tr><tr><td style="text-align:right;">MT_CKD water-vapor continuum</td><td style="text-align:right;"><code>h2o_continuum</code></td><td style="text-align:right;">cm²/molecule</td></tr><tr><td style="text-align:right;">CIA binary cross-section</td><td style="text-align:right;"><code>cia_cross_section</code></td><td style="text-align:right;">cm⁵/molecule²</td></tr></tbody></table><p>In both cases the package returns a cross-section, never an optical depth. Combine with number densities (× path length) in your RT code to build τ(ν).</p></div></div>`,10)])])}const u=i(n,[["render",l]]);export{k as __pageData,u as default};
